<?php
require_once __DIR__.'/app/layout.php'; require_login();
$admin=is_admin(); $own=$admin?null:require_operator_employee_id();
$month=$_GET['month']??date('Y-m'); $where=['DATE_FORMAT(a.event_date,"%Y-%m")=?']; $params=[$month];
if($admin){ $employee=(int)($_GET['employee_id']??0); if($employee){$where[]='a.employee_id=?';$params[]=$employee;} $emps=db()->query('SELECT id,name FROM employees WHERE active=1 ORDER BY name')->fetchAll(); }
else { $employee=$own; $where[]='a.employee_id=?';$params[]=$own; $st=db()->prepare('SELECT id,name FROM employees WHERE id=?');$st->execute([$own]);$emps=$st->fetchAll(); }
$sql='SELECT a.*,e.name FROM attendance_events a JOIN employees e ON e.id=a.employee_id WHERE '.implode(' AND ',$where).' ORDER BY a.event_date DESC,a.id DESC';$st=db()->prepare($sql);$st->execute($params);$rows=$st->fetchAll();
page_header('Riwayat & Surat','events');?><div class="card"><div class="section-title"><h2>Riwayat Kejadian</h2><div class="actions-inline"><a class="btn secondary" href="export_csv.php?employee_id=<?=$employee?>&month=<?=e($month)?>">Ekspor CSV</a><a class="btn" href="event_form.php">Tambah</a></div></div><form method="get" class="form-grid" style="margin-bottom:14px"><?php if($admin):?><div class="field"><label>Pegawai</label><select name="employee_id"><option value="0">Semua pegawai</option><?php foreach($emps as $e):?><option value="<?=$e['id']?>" <?=$employee===$e['id']?'selected':''?>><?=e($e['name'])?></option><?php endforeach;?></select></div><?php else:?><div class="field"><label>Pegawai</label><input value="<?=e($emps[0]['name']??'')?>" disabled></div><?php endif;?><div class="field"><label>Bulan</label><input type="month" name="month" value="<?=e($month)?>"></div><div class="form-actions full"><button class="btn secondary">Terapkan filter</button></div></form><div class="table-wrap"><table class="data"><thead><tr><th>Tanggal</th><th>Pegawai</th><th>Kategori</th><th>Pukul</th><th>Nomor</th><th>Status</th><th>Aksi</th></tr></thead><tbody><?php if(!$rows):?><tr><td colspan="7" class="empty">Belum ada data.</td></tr><?php else:foreach($rows as $r):?><tr><td><?=e(date_formal($r['event_date']))?></td><td><?=e($r['name'])?></td><td><?=e(categories()[$r['category']])?></td><td><?=e(substr($r['event_time'],0,5))?></td><td><?=e($r['letter_number']?:'-')?></td><td><span class="badge <?=$r['approval_status']==='approved'?'ok':($r['approval_status']==='rejected'?'danger':'warn')?>"><?=e(approval_labels()[$r['approval_status']])?></span></td><td><div class="actions-inline"><a class="btn secondary small" href="letter.php?id=<?=$r['id']?>">Surat</a><a class="btn ghost small" href="event_form.php?id=<?=$r['id']?>">Ubah</a><form method="post" action="event_delete.php" style="display:inline"><?=csrf_input()?><input type="hidden" name="id" value="<?=$r['id']?>"><button class="btn danger small" data-confirm="Hapus kejadian ini?">Hapus</button></form></div></td></tr><?php endforeach;endif;?></tbody></table></div></div><?php page_footer();
